@app.route("/login", methods=["POST"])
def login():
    """Handles user login and issues a token."""
    data = request.get_json()
    username = data.get("username")
    password = data.get("password")

    if not username or not password:
        return jsonify({"message": "Username and password are required."}), 400

    user = users_db.get(username)
    if user and user["password"] == password:
        token = generate_token(username)
        return jsonify({"message": "Login successful", "token": token}), 200
    else:
        return jsonify({"message": "Invalid credentials"}), 401

@app.route("/logout", methods=["POST"])
@token_required
def logout(current_user):
    """Handles user logout and revokes the current token."""
    token = request.headers["Authorization"].split(" ", 1)[1]
    try:
        payload = jwt.decode(token, SECRET_KEY, algorithms=["HS256"], options={"verify_signature": False})
        token_id = payload.get("jti")
        if token_id in active_tokens:
            del active_tokens[token_id]
            return jsonify({"message": "Logged out successfully. Token revoked."}), 200
        else:
            return jsonify({"message": "Token not found or already revoked."}), 400
    except Exception as e:
        return jsonify({"message": f"Error during logout: {e}"}), 500

